import { TAU, SAMPLE_RATE, SAMPLE_RATE_RECIP, AI_MODULES_KEY } from './constants';
import { Module } from './module';
import { Signal, scalar } from './signal';
import { transform } from 'sucrase';

// Organization in local storage:
// ai-modules: a comma-separated list of module names (in order of creation)
// ai-modules-<name>: the TypeScript code for the module

let aiModules: Record<string, Module<any>> | null = null;

export function getAiModules() {
  if (!aiModules) {
    updateAiModules(getAiModulesCode());
  }
  return aiModules;
}

export function updateAiModules(modules: { name: string; code: string }[]) {
  aiModules = {};
  for (const { name, code } of modules) {
    aiModules[name] = makeAiModule(name, code);
  }
  return aiModules;
}

export function getAiModulesCode(): { name: string; code: string }[] {
  return getAiModuleNames()
    .map(name => ({ name, code: localStorage.getItem(`ai-modules-${name}`) }))
    .filter(m => m.code !== null);
}

function getAiModuleNames() {
  return localStorage.getItem(AI_MODULES_KEY)?.split(',') ?? [];
}

function makeAiModule(name: string, tsSource: string): Module<any> {
  const jsSource = transform('return ' + tsSource, {
    transforms: ['typescript'],
  }).code;
  const fn = new Function(
    'Module',
    'TAU',
    'SAMPLE_RATE',
    'SAMPLE_RATE_RECIP',
    'Signal',
    'scalar',
    jsSource
  );
  return fn(Module, TAU, SAMPLE_RATE, SAMPLE_RATE_RECIP, Signal, scalar);
}

// called by the AI directly
export function addAiModule(name: string, tsCode: string): string {
  console.log('llm adding ai module:', name, tsCode);

  getAiModules()[name] = makeAiModule(name, tsCode);

  const names = getAiModuleNames();
  if (names.includes(name)) {
    names.splice(names.indexOf(name), 1);
  }
  names.push(name);

  localStorage.setItem(AI_MODULES_KEY, names.join(','));
  localStorage.setItem(`ai-modules-${name}`, tsCode);
  return name;
}

export function saveAiModulePromptAndTranscript(name: string, prompt: string, transcript: string) {
  localStorage.setItem(`ai-modules-prompt-${name}`, prompt);
  localStorage.setItem(`ai-modules-transcript-${name}`, transcript);
}
