import type { Position } from './types';

import * as ui from './ui-constants';
import { Font } from './ui-constants';
import { TAU } from './constants';
import { canvas, ctx, showStatus } from './canvas';
import { clamp } from './helpers';
import { drawMaterialOverlay } from './ui-texture';
import { ensureWebAudioInitialized } from './audio';

export type PosHint =
  | 'next'
  | 'top left'
  | 'top center'
  | 'top right'
  | 'bottom left'
  | 'bottom center'
  | 'bottom right'
  | 'as is';

export interface ThingOptions {
  x?: () => number;
  y?: () => number;
  w?: () => number;
  h?: () => number;
  layoutMode?: 'row' | 'column' | 'none';
  hasBackground?: boolean;
}

export abstract class Thing<Options extends ThingOptions = ThingOptions> {
  protected parent: Thing | null = null;
  protected readonly children: Thing[] = [];
  protected readonly posHints: PosHint[] = [];
  public x = 0;
  public y = 0;
  public w = 0;
  public h = 0;

  constructor(public readonly options: Options) {}

  addChild(child: Thing, posHint: PosHint = 'next'): this {
    child.parent = this;
    this.children.push(child);
    this.posHints.push(posHint);
    this.layout();
    return this;
  }

  replaceChild(oldChild: Thing, newChild: Thing): this {
    const index = this.children.indexOf(oldChild);
    if (index === -1) {
      throw new Error('oldChild not found');
    }
    this.children[index] = newChild;
    newChild.parent = this;
    this.layout();
    return this;
  }

  // ----- position and size -----

  layout() {
    let nextX = this.x;
    let nextY = this.y;
    for (let idx = 0; idx < this.children.length; idx++) {
      const child = this.children[idx];
      const posHint = this.posHints[idx];

      child.x = child.options.x?.() ?? child.x;
      child.y = child.options.y?.() ?? child.y;
      child.w = child.options.w?.() ?? child.w;
      child.h = child.options.h?.() ?? child.h;

      switch (posHint) {
        case 'next':
          child.x = nextX;
          child.y = nextY;
          switch (this.options.layoutMode ?? 'none') {
            case 'row':
              child.h = this.h;
              nextX += child.w;
              break;
            case 'column':
              child.w = this.w;
              nextY += child.h;
              break;
            case 'none':
              throw new Error('cannot have a child w/ posHint "next" when layoutMode is "none"');
          }
          break;
        case 'top left':
          child.x = this.x;
          child.y = this.y;
          break;
        case 'top center':
          child.x = this.centerX - child.w / 2;
          child.y = this.y;
          break;
        case 'top right':
          child.x = this.rightX - child.w;
          child.y = this.y;
          break;
        case 'bottom left':
          child.x = this.x;
          child.y = this.bottomY - child.h;
          break;
        case 'bottom center':
          child.x = this.centerX - child.w / 2;
          child.y = this.bottomY - child.h;
          break;
        case 'bottom right':
          child.x = this.rightX - child.w;
          child.y = this.bottomY - child.h;
          break;
        case 'as is':
          // leave child.x and child.y alone
          break;
      }
      child.layout();
    }
  }

  get bottomY() {
    return this.y + this.h;
  }

  get rightX() {
    return this.x + this.w;
  }

  get centerY() {
    return this.y + this.h / 2;
  }

  get centerX() {
    return this.x + this.w / 2;
  }

  contains(x: number, y: number) {
    return this.x <= x && x <= this.rightX && this.y <= y && y <= this.bottomY;
  }

  // rendering

  render() {
    if (this.options.hasBackground) {
      ctx.beginPath();
      ctx.fillStyle = ui.GROUT_COLOR;
      ctx.rect(this.x, this.y, this.w, this.h);
      ctx.fill();

      ctx.beginPath();
      ctx.fillStyle = this.lightBackgroundColor;
      ctx.roundRect(this.x + 1, this.y + 1, this.w - 2, this.h - 2, ui.RECTANGLE_RADIUS);
      ctx.fill();

      drawMaterialOverlay(this.x + 1, this.y + 1, this.w - 2, this.h - 2, ui.RECTANGLE_RADIUS);
    }
  }

  /** Subclasses may override this method to render overlays, etc. */
  renderOnTop() {}

  /** This method should be `final`, but that doesn't exist in TypeScript :/ */
  recursiveRender() {
    ctx.save();
    ctx.beginPath();
    ctx.rect(this.x, this.y, this.w, this.h);
    ctx.clip();

    ctx.save();
    this.render();
    ctx.restore();

    for (const child of this.children) {
      child.recursiveRender();
    }

    ctx.restore();
  }

  /**
   * Unlike render(), renderOnTop() doesn't clip. It also does the children before the parent.
   * This method should be `final`, but that doesn't exist in TypeScript :/
   */
  recursiveRenderOnTop() {
    for (const child of this.children) {
      child.recursiveRenderOnTop();
    }

    ctx.save();
    this.renderOnTop();
    ctx.restore();
  }

  // event handling

  /** Returns `true` if the event was handled here. */
  onPointerDown(x: number, y: number, e: PointerEvent): boolean | void {}

  onPointerMove(x: number, y: number, e: PointerEvent): void {}

  onPointerUp(x: number, y: number, e: PointerEvent): void {}

  /** This method should be `final`, but that doesn't exist in TypeScript :/ */
  recursiveOnPointerDown(x: number, y: number, e: PointerEvent): Thing | null {
    if (!this.contains(x, y)) {
      return null;
    }

    for (const child of this.children) {
      const handled = child.recursiveOnPointerDown(x, y, e);
      if (handled) {
        return handled;
      }
    }

    const handled = this.onPointerDown(x, y, e);
    return handled ? this : null;
  }

  // colors, etc.

  get backgroundColor() {
    return ui.DARK_BACKGROUND_COLOR;
  }

  get lightBackgroundColor() {
    return ui.LIGHT_BACKGROUND_COLOR;
  }

  get foregroundColor() {
    return ui.TEXT_COLOR;
  }

  // helpers

  textWidth(text: string, font: Font) {
    ctx.save();
    ctx.font = font.cssFontString;
    const width = ctx.measureText(text).width;
    ctx.restore();
    return width;
  }

  renderLabel(
    label: string,
    font = Font.button,
    x?: number,
    y?: number,
    color?: string,
    alpha?: number
  ) {
    ctx.save();
    ctx.globalAlpha = alpha ?? 1;
    ctx.beginPath();
    ctx.font = font.cssFontString;
    ctx.fillStyle = color ?? this.foregroundColor;
    const px = x ?? this.centerX;
    const py = y ?? this.centerY;
    ctx.fillText(label, px - ctx.measureText(label).width / 2, py + font.baselineAdjustment);
    ctx.fill();
    ctx.restore();
  }
}

export const topLevelThing = new (class extends Thing {
  constructor() {
    super({
      layoutMode: 'none',
      x: () => 0,
      y: () => 0,
      w: () => innerWidth,
      h: () => innerHeight,
    });
  }

  recursiveRender() {
    const w = this.options.w!();
    const h = this.options.h!();
    if (this.w !== w || this.h !== h) {
      this.w = w;
      this.h = h;
      this.layout();
    }

    super.recursiveRender();
  }
})();

export class Slot extends Thing {
  private currentChild: Thing;

  constructor(private readonly supplier: () => Thing) {
    super({
      layoutMode: 'none',
      w: () => this.childSize().w,
      h: () => this.childSize().h,
    });
    this.currentChild = this.supplier();
    this.addChild(this.currentChild, 'top left');
  }

  /** Ensures the child has dimensions before we report our size (parent asks before layout runs). */
  private childSize(): { w: number; h: number } {
    const c = this.children[0];
    if (!c) {
      return { w: 0, h: 0 };
    }
    const w = c.options.w?.() ?? c.w;
    const h = c.options.h?.() ?? c.h;
    return { w, h };
  }

  layout() {
    const c = this.children[0];
    if (c) {
      // Slot's child must fill the slot; parent allocates our w/h, so assign them to the child.
      // Otherwise children without explicit options.h (e.g. Display/Tool) stay at h=0 and get clipped.
      c.w = this.w;
      c.h = this.h;
    }
    super.layout();
  }

  /** Called each frame before render; updates the child if the supplier returns a different Thing. */
  recursiveRender() {
    const next = this.supplier();
    if (next !== this.currentChild) {
      this.replaceChild(this.currentChild, next);
      this.currentChild = next;
      this.parent?.layout(); // propagate layout up when content changes size
    }
    super.recursiveRender();
  }
}

export class Row extends Thing {
  constructor(options: ThingOptions) {
    super({
      layoutMode: 'row',
      w: () => this.children.reduce((acc, child) => acc + child.w, 0),
      ...options,
    });
  }
}

export class Column extends Thing {
  constructor(options: ThingOptions) {
    super({
      layoutMode: 'column',
      h: () => this.children.reduce((acc, child) => acc + child.h, 0),
      ...options,
    });
  }
}

interface ButtonOptions extends ThingOptions {
  label: () => string;
  pointerDownFn?: () => void;
  pointerUpFn?: () => void;
}

export class Button extends Thing<ButtonOptions> {
  constructor(options: ButtonOptions) {
    super({ hasBackground: true, ...options });
  }

  render() {
    super.render();
    this.renderLabel(this.options.label());
  }

  onPointerDown() {
    this.options.pointerDownFn?.();
    return true;
  }

  onPointerUp() {
    this.options.pointerUpFn?.();
  }
}

export interface KnobOptions extends ThingOptions {
  label: string;
  getValue: () => number;
  setValue: (x: number) => void;
  sensitivity?: () => number;
  color: () => string;
}

export class Knob<Options extends KnobOptions = KnobOptions> extends Thing<Options> {
  constructor(options: Options) {
    super({ hasBackground: true, ...options });
  }

  render() {
    super.render();

    const radius = 0.3 * Math.min(this.w, this.h);

    ctx.lineWidth = 6;

    ctx.globalAlpha = 0.15;
    ctx.beginPath();
    ctx.strokeStyle = this.options.color();
    ctx.lineCap = 'butt';
    ctx.arc(this.centerX, this.centerY, radius, 0, TAU);
    ctx.stroke();

    ctx.globalAlpha = 1;
    ctx.beginPath();
    ctx.arc(this.centerX, this.centerY, radius, TAU / 4, TAU * this.value + TAU / 4);
    ctx.stroke();

    this.renderLabel(this.options.label, Font.label);
  }

  get value() {
    return this.options.getValue();
  }

  set value(newValue: number) {
    this.options.setValue(newValue);
  }

  private angle0: number | null = null;
  private sensitivity0: number | null = null;
  private isTouch = false;

  renderOnTop(): void {
    if (!this.angle0 || !this.isTouch) {
      return;
    }

    ctx.save();
    ctx.globalAlpha = 0.8;
    const dir = this.rightX > innerWidth / 2 ? -1 : 1;
    ctx.translate(dir * 1.25 * this.w, innerHeight / 4 - this.y);
    this.render();
    ctx.restore();
  }

  onPointerDown(x: number, y: number, { pointerType }: PointerEvent) {
    this.angle0 = Math.atan2(y - this.centerY, x - this.centerX);
    this.sensitivity0 = this.sensitivity;
    this.isTouch = pointerType === 'touch';
    return true;
  }

  onPointerMove(x: number, y: number) {
    const newAngle = Math.atan2(y - this.centerY, x - this.centerX);
    if (this.sensitivity0 !== this.sensitivity) {
      this.sensitivity0 = this.sensitivity;
    } else {
      const diff = ((((newAngle - this.angle0! + Math.PI) % TAU) + TAU) % TAU) - Math.PI;
      const value = clamp(this.value + diff / this.sensitivity / TAU, 0, 1);
      this.options.setValue(value);
      showStatus(`${this.options.label} = ${value.toFixed(2)}`);
    }
    this.angle0 = newAngle;
  }

  onPointerUp(x: number, y: number): void {
    this.angle0 = null;
    this.sensitivity0 = null;
  }

  private get sensitivity() {
    return this.options.sensitivity?.() ?? 1;
  }
}

export interface JoystickOptions extends ThingOptions {
  label: string;
  getXValue: () => number;
  setXValue: (x: number) => void;
  getYValue: () => number;
  setYValue: (y: number) => void;
  color: () => string;
  parallaxAdjustment?: { x: number; y: number };
}

export class Joystick<Options extends JoystickOptions = JoystickOptions> extends Thing<Options> {
  private static readonly radius = 12;

  constructor(options: Options) {
    super({ hasBackground: true, ...options });
  }

  get size() {
    return Math.min(this.w, this.h) * 0.6;
  }

  render() {
    super.render();

    ctx.globalAlpha = 1;
    const font = Font.joystick;
    ctx.font = font.cssFontString;
    const width = ctx.measureText(this.options.label).width;
    this.renderLabel(
      this.options.label,
      font,
      this.rightX - width / 2 - 4,
      this.bottomY - font.sizeInPixels
    );

    ctx.globalAlpha = 0.15;
    ctx.strokeStyle = this.options.color();
    ctx.lineWidth = Joystick.radius;
    ctx.lineCap = 'round';
    ctx.moveTo(this.centerX, this.centerY);
    ctx.lineTo(this.cx, this.cy);
    ctx.stroke();
  }

  renderEndpoint() {
    ctx.fillStyle = this.options.color();
    ctx.beginPath();
    ctx.arc(this.cx, this.cy, 0.8 * Joystick.radius, 0, TAU);
    ctx.fill();
  }

  renderOnTop(): void {
    this.renderEndpoint();

    if (!this.pos0 || !this.isTouch) {
      return;
    }

    ctx.save();
    ctx.globalAlpha = 1;
    const dir = this.rightX > innerWidth / 2 ? -1 : 1;
    ctx.translate(dir * 1.25 * this.w, innerHeight / 4 - this.y);
    this.render();
    this.renderEndpoint();
    ctx.restore();
  }

  private get cx() {
    const xValue = this.options.getXValue();
    return (
      this.centerX +
      (xValue * this.size) / 2 +
      (this.options.parallaxAdjustment?.x ?? 0) * this.size
    );
  }

  private get cy() {
    const yValue = this.options.getYValue();
    return (
      this.centerY -
      (yValue * this.size) / 2 +
      (this.options.parallaxAdjustment?.y ?? 0) * this.size
    );
  }

  private pos0: Position | null = null;
  private value0: Position | null = null;
  private isTouch = false;

  onPointerDown(x: number, y: number, { pointerType }: PointerEvent) {
    this.pos0 = { x, y };
    this.value0 = { x: this.options.getXValue(), y: this.options.getYValue() };
    this.isTouch = pointerType === 'touch';
    return true;
  }

  onPointerMove(x: number, y: number) {
    const xv = clamp(this.value0!.x + ((x - this.pos0!.x) / this.size) * 2, -1, 1);
    const yv = clamp(this.value0!.y - ((y - this.pos0!.y) / this.size) * 2, -1, 1);
    this.setValue(xv, yv);
  }

  onPointerUp(x: number, y: number) {
    this.pos0 = null;
    this.value0 = null;
    this.setValue(0, 0);
  }

  private setValue(x: number, y: number) {
    this.options.setXValue(x);
    this.options.setYValue(y);
    showStatus(`${this.options.label} = (${x.toFixed(2)}, ${y.toFixed(2)})`);
  }
}

export interface LabelOptions extends ThingOptions {
  label: () => string;
  color?: () => string;
  onPointerDown?: () => void;
  onPointerUp?: () => void;
  border?: boolean;
}

export class Label<Options extends LabelOptions = LabelOptions> extends Thing<Options> {
  static new<Options extends LabelOptions>(options: Options): Label<LabelOptions> {
    return new Label(options);
  }

  constructor(options: Options) {
    super({
      w: () => this.textWidth(this.options.label()) + 2 * ui.LABEL_PADDING,
      h: () => Font.label.sizeInPixels + 2 * ui.LABEL_PADDING,
      ...options,
    });
  }

  onPointerDown(x: number, y: number, e: PointerEvent) {
    this.options.onPointerDown?.();
    return true;
  }

  onPointerUp(x: number, y: number, e: PointerEvent) {
    this.options.onPointerUp?.();
  }

  get foregroundColor() {
    return this.options.color?.() ?? this.foregroundColor;
  }

  render() {
    this.parent.layout();
    if (this.options.border) {
      ctx.beginPath();
      ctx.fillStyle = this.foregroundColor;
      ctx.lineWidth = 2;
      const d = Font.label.sizeInPixels / 1.8;
      ctx.roundRect(
        this.x + d,
        this.y + d,
        this.w - 2 * d,
        this.h - 2 * d,
        ui.RECTANGLE_RADIUS * 2
      );
      ctx.fill();
      ctx.fillStyle = '#000';
      ctx.font = Font.label.cssFontString;
      ctx.fillText(
        this.options.label(),
        this.x + this.w / 2 - ctx.measureText(this.options.label()).width / 2,
        this.y + this.h / 2 + Font.label.baselineAdjustment
      );
    } else {
      this.renderLabel(this.options.label(), Font.label);
    }
  }

  textWidth(text: string, font = Font.label) {
    return super.textWidth(text, font);
  }
}

interface EmbeddedSelectorOptions<T> extends LabelOptions {
  values: readonly T[];
  getValue: () => T;
  setValue: (value: T) => void;
  valueToString: (value: T) => string;
  placeCurrentValueAtY0?: boolean;
}

export class EmbeddedSelector<T> extends Label<EmbeddedSelectorOptions<T>> {
  private readonly lineSpacing = 1.25;
  private readonly labels: string[];
  private readonly maxLabelWidth: number;

  constructor(
    options: Omit<EmbeddedSelectorOptions<T>, 'label' | 'onPointerDown' | 'onPointerUp'>
  ) {
    super({
      label: () => this.options.valueToString(this.options.getValue()),
      color: () => ui.EMBEDDED_SELECTOR_VALUE_COLOR,
      ...options,
    });

    const { values, valueToString, placeCurrentValueAtY0 } = options;

    this.labels = values.map(valueToString);
    if (!placeCurrentValueAtY0) {
      this.labels.unshift('');
    }

    this.maxLabelWidth =
      this.labels.map(label => this.textWidth(label)).reduce((a, b) => Math.max(a, b)) +
      2 * ui.LABEL_PADDING;
  }

  private pointerPos?: { initial: Position; current: Position };
  private popUp?: { x: number; y: number; w: number; h: number };
  private selection?: { x: number; y0: number };

  onPointerDown(x: number, y: number) {
    this.pointerPos = { initial: { x, y }, current: { x, y } };

    const goRight = this.pointerPos.initial.x < innerWidth / 2;

    const w = 1.125 * ui.SELECTOR_FINGER_WIDTH + this.maxLabelWidth;
    this.popUp = {
      w,
      h: (this.labels.length + 0.5) * Font.label.sizeInPixels * this.lineSpacing,
      x: goRight
        ? this.pointerPos.initial.x - ui.SELECTOR_FINGER_WIDTH / 2
        : this.pointerPos.initial.x - w + ui.SELECTOR_FINGER_WIDTH / 2,
      y: this.pointerPos.initial.y - Font.label.sizeInPixels,
    };

    if (this.options.placeCurrentValueAtY0) {
      this.popUp.y -=
        Font.label.sizeInPixels * this.options.values.indexOf(this.options.getValue());
    }

    this.selection = {
      x: this.popUp.x + (goRight ? ui.SELECTOR_FINGER_WIDTH : 0.125 * ui.SELECTOR_FINGER_WIDTH),
      y0: this.popUp.y + (this.options.placeCurrentValueAtY0 ? 0 : Font.label.sizeInPixels),
    };

    return true;
  }

  onPointerMove(x: number, y: number) {
    this.pointerPos!.current.x = x;
    this.pointerPos!.current.y = y;
    const firstValueY =
      this.popUp.y + (this.options.placeCurrentValueAtY0 ? 1 : 2) * Font.label.sizeInPixels;
    const selectedValueIdx = Math.round(
      (y - firstValueY) / (Font.label.sizeInPixels * this.lineSpacing)
    );
    if (selectedValueIdx < 0) {
      return;
    }
    const selectedValue =
      this.options.values[Math.min(selectedValueIdx, this.options.values.length - 1)];
    if (selectedValue !== this.options.getValue()) {
      this.options.setValue(selectedValue);
      this.parent.layout(); // necessary b/c our width changes
    }
  }

  onPointerUp(x: number, y: number): void {
    this.pointerPos = undefined;
  }

  renderOnTop() {
    if (!this.pointerPos) {
      return;
    }

    ctx.fillStyle = 'rgba(255, 255, 255, 0.75)';
    ctx.filter = 'drop-shadow(2px 2px 2px)';
    ctx.beginPath();
    ctx.roundRect(this.popUp.x, this.popUp.y, this.popUp.w, this.popUp.h, ui.RECTANGLE_RADIUS);
    ctx.fill();
    ctx.filter = 'none';

    ctx.filter = 'blur(5px)';
    ctx.fillStyle = 'rgba(255, 255, 255, 0.8)';
    ctx.beginPath();
    ctx.roundRect(this.popUp.x, this.popUp.y, this.popUp.w, this.popUp.h, ui.RECTANGLE_RADIUS);
    ctx.fill();
    ctx.filter = 'none';

    ctx.font = Font.label.cssFontString;
    let valueY = this.selection.y0;
    for (const value of this.options.values) {
      valueY += Font.label.sizeInPixels * this.lineSpacing;
      this.renderValue(
        this.options.valueToString(value),
        this.options.getValue() === value,
        this.selection.x,
        valueY
      );
    }
  }

  renderValue(label: string, isCurrent: boolean, x: number, y: number) {
    if (isCurrent) {
      ctx.beginPath();
      ctx.fillStyle = ui.MID_BACKGROUND_COLOR;
      ctx.roundRect(
        x - ui.LABEL_PADDING,
        y - Font.label.sizeInPixels,
        this.maxLabelWidth + 2 * ui.LABEL_PADDING,
        Font.label.sizeInPixels + Font.label.baselineAdjustment,
        ui.RECTANGLE_RADIUS
      );
      ctx.fill();
    }

    ctx.beginPath();
    ctx.fillStyle = isCurrent ? '#000' : '#777';
    ctx.fillText(label, x, y);
    ctx.fill();
  }
}

// handling pointer events

const pointerIdToThing = new Map<number, Thing>();

canvas.addEventListener('pointerdown', e => {
  ensureWebAudioInitialized();
  const thing = topLevelThing.recursiveOnPointerDown(e.offsetX, e.offsetY, e);
  if (thing) {
    pointerIdToThing.set(e.pointerId, thing);
    canvas.setPointerCapture(e.pointerId);
    e.preventDefault();

    // always calling onPointerMove after onPointerDown makes my code nicer
    thing.onPointerMove(e.offsetX, e.offsetY, e);
  }
});

canvas.addEventListener('pointermove', e => {
  const thing = pointerIdToThing.get(e.pointerId);
  if (thing) {
    thing.onPointerMove(e.offsetX, e.offsetY, e);
    e.preventDefault();
  }
});

canvas.addEventListener('pointerup', onPointerUp);
canvas.addEventListener('pointercancel', onPointerUp);

function onPointerUp(e: PointerEvent) {
  const thing = pointerIdToThing.get(e.pointerId);
  if (thing) {
    thing.onPointerUp(e.offsetX, e.offsetY, e);
    pointerIdToThing.delete(e.pointerId);
    e.preventDefault();
  }
  canvas.releasePointerCapture(e.pointerId);
}

export abstract class Display<Options extends ThingOptions = ThingOptions> extends Thing<Options> {
  constructor(options: Options) {
    super({ hasBackground: true, ...options });
  }

  abstract renderDisplay(): void;

  get displayX() {
    return this.x + 4;
  }

  get displayY() {
    return this.y + 4;
  }

  get displayW() {
    return this.w - 8;
  }

  get displayH() {
    return this.h - 8;
  }

  render() {
    super.render();

    ctx.save();
    ctx.beginPath();
    ctx.roundRect(this.displayX, this.displayY, this.displayW, this.displayH, ui.RECTANGLE_RADIUS);
    ctx.clip();

    // dark background
    ctx.fillStyle = ui.DISPLAY_BACKGROUND_COLOR;
    ctx.fillRect(this.displayX, this.displayY, this.displayW, this.displayH);

    this.renderDisplay();

    ctx.restore();
  }
}
